{"code":"import json
import pandas as pd

# Load data
case_owners_data = locals()['var_function-call-17657878652496307354']
with open(locals()['var_function-call-5796599664818877858'], 'r') as f:
    case_history_data = json.load(f)

def clean_id(i):
    if i and isinstance(i, str):
        if i.startswith('#'):
            return i[1:]
        return i
    return i

start_date = pd.Timestamp("2022-04-10", tz='UTC')
end_date = pd.Timestamp("2023-04-10", tz='UTC')

handlers_lifetime = set()
for row in case_owners_data:
    oid = clean_id(row.get('ownerid'))
    if oid: handlers_lifetime.add(oid)

for row in case_history_data:
    old_val = clean_id(row.get('oldvalue__c'))
    new_val = clean_id(row.get('newvalue__c'))
    if old_val and old_val != "None": handlers_lifetime.add(old_val)
    if new_val and new_val != "None": handlers_lifetime.add(new_val)

transfer_counts = {}
handlers_in_period = set()

for row in case_history_data:
    old_val = clean_id(row.get('oldvalue__c'))
    new_val = clean_id(row.get('newvalue__c'))
    c_date_str = row.get('createddate')
    field = row.get('field__c')

    try:
        c_date = pd.to_datetime(c_date_str)
        if c_date.tzinfo is None: c_date = c_date.tz_localize('UTC')

        if start_date <= c_date <= end_date:
            if field == 'Owner Assignment':
                # Track handlers in period
                if old_val and old_val != "None": handlers_in_period.add(old_val)
                if new_val and new_val != "None": handlers_in_period.add(new_val)

                # Count transfers (outgoing)
                if old_val and old_val != "None":
                    transfer_counts[old_val] = transfer_counts.get(old_val, 0) + 1
    except:
        pass

# Check candidates from handlers_in_period
candidates = []
for h in handlers_in_period:
    count = transfer_counts.get(h, 0)
    candidates.append((h, count))

candidates.sort(key=lambda x: x[1])

if not candidates:
    # If no one handled cases in period? 
    # Fallback to lifetime handlers? 
    # But if no one handled in period, transfer counts are 0 for everyone.
    pass

result = {
    "num_candidates_in_period": len(candidates),
    "top_candidates": candidates[:10]
}

print("__RESULT__:")
print(json.dumps(result))"}

